      <button type="submit" style={{ width: '100%', padding: '12px', border: 'none', borderRadius: '6px', backgroundColor: '#6366f1', color: '#fff', fontWeight: 600, cursor: 'pointer' }}>{saved ? 'Saved!' : 'Save Changes'}</button>
